import{c as a,Q as s,j as t,m as n}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"The /pause kill-switch","description":"One tap. ≤1 Arbitrum block. Global across all four surfaces.","frontmatter":{"title":"The /pause kill-switch","description":"One tap. ≤1 Arbitrum block. Global across all four surfaces."},"headers":[],"relativePath":"policy/pause.md","filePath":"policy/pause.md","lastUpdated":1778983454000}'),o={name:"policy/pause.md"};function i(r,e,l,u,p,c){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="the-pause-kill-switch" tabindex="-1">The /pause kill-switch <a class="header-anchor" href="#the-pause-kill-switch" aria-label="Permalink to &quot;The /pause kill-switch&quot;">​</a></h1><p><code>/pause</code> is MuHaven&#39;s <strong>single-tx kill-switch</strong>. It uninstalls your MuHaven wallet&#39;s session-key validator in <strong>≤1 Arbitrum block</strong>. After it fires, every <code>propose</code> tool on every surface returns <code>423 PAUSED</code> until you explicitly resume.</p><p>It&#39;s the same surface across HavenBot, MCP, OpenClaw, and the audit copilot — one command, one tx, global effect.</p><h2 id="how-to-pause" tabindex="-1">How to pause <a class="header-anchor" href="#how-to-pause" aria-label="Permalink to &quot;How to pause&quot;">​</a></h2><p>Any of these works:</p><ul><li><strong>HavenBot:</strong> <em>&quot;Pause my agent.&quot;</em></li><li><strong>MCP:</strong> <code>muhaven.policy.pause</code> (no args).</li><li><strong>Telegram:</strong> <code>/pause</code>.</li><li><strong>Dashboard:</strong> <code>/agent → Pause button</code> (top-right red button).</li></ul><p>The pause command is <strong>idempotent</strong>: calling it on an already-paused agent is a no-op (returns <code>200 OK</code> with <code>result: &#39;already_paused&#39;</code>).</p><h2 id="what-pause-does-mechanically" tabindex="-1">What pause does mechanically <a class="header-anchor" href="#what-pause-does-mechanically" aria-label="Permalink to &quot;What pause does mechanically&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You call pause</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ Backend PauseAgentUseCase                                    │</span></span>
<span class="line"><span>│   1. Validate the request (auth, scope)                      │</span></span>
<span class="line"><span>│   2. Mint an unsigned UserOp:                                │</span></span>
<span class="line"><span>│       to: yourKernelAddress                                  │</span></span>
<span class="line"><span>│       data: uninstallPlugin(sessionKeyValidatorAddress)      │</span></span>
<span class="line"><span>│   3. Sign with the master passkey (Advisory tier)            │</span></span>
<span class="line"><span>│      OR the session key itself (Confirm-per-action — yes,    │</span></span>
<span class="line"><span>│      the session key can uninstall itself, last action)      │</span></span>
<span class="line"><span>│   4. Submit via ZeroDev bundler                              │</span></span>
<span class="line"><span>│   5. Wait for inclusion (~1 block)                            │</span></span>
<span class="line"><span>│   6. Write audit row: pause_triggered                        │</span></span>
<span class="line"><span>│   7. Cascade pause to all surface-specific state             │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       │ tx settled</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>   Session-key validator no longer in your MuHaven wallet&#39;s plugin set</span></span>
<span class="line"><span>   Every propose UserOp through the session key now fails:</span></span>
<span class="line"><span>     &quot;0x14eac17b&quot; (PluginUninstalled)</span></span></code></pre></div><h2 id="pause-cascade" tabindex="-1">Pause cascade <a class="header-anchor" href="#pause-cascade" aria-label="Permalink to &quot;Pause cascade&quot;">​</a></h2><p>Pausing cascades across surfaces (T-1 through T-7 in the backend&#39;s <code>PauseAgentUseCase</code>):</p><table tabindex="0"><thead><tr><th>Step</th><th>What happens</th></tr></thead><tbody><tr><td>T-1</td><td>On-chain validator uninstall (the tx above)</td></tr><tr><td>T-2</td><td>Backend marks user state <code>paused=true</code> in <code>agent_user_state</code></td></tr><tr><td>T-3</td><td>Cron policy engine drops the user from its scheduled tick set</td></tr><tr><td>T-4</td><td>Open SSE connections (HavenBot chat, checkout buyer-side) receive a <code>pause</code> event</td></tr><tr><td>T-5</td><td>Audit row written</td></tr><tr><td>T-6</td><td>Webhook subscribers (issuer-side checkout webhooks) receive a <code>policy.paused</code> event</td></tr><tr><td>T-7</td><td>Idempotency guard set so a concurrent pause call is a no-op</td></tr></tbody></table><p>The cascade ensures consistency — a chat session that was mid-conversation when pause fires will see the pause notification in the next stream chunk; a checkout that was waiting for buyer settlement will not block forever (it returns <code>paused</code> to the buyer).</p><h2 id="what-pause-prevents" tabindex="-1">What pause prevents <a class="header-anchor" href="#what-pause-prevents" aria-label="Permalink to &quot;What pause prevents&quot;">​</a></h2><p>Once paused, the <strong>session key cannot sign anything</strong>. That means:</p><ul><li>❌ Buy / sell / claim / rebalance through any surface.</li><li>❌ Set policy / set tier (these are tier transitions; require passkey resume first).</li><li>❌ Distribute yield / KYC add / KYC remove / unpause token (issuer side — same session key).</li><li>❌ Create checkout link (issuer side).</li><li>❌ Cast governance vote.</li></ul><p>What still works:</p><ul><li>✅ All read tools (portfolio, yields, audit, etc.).</li><li>✅ Sign in / sign out (the master passkey is unaffected).</li><li>✅ Read your audit log including the <code>pause_triggered</code> row.</li><li>✅ The buyer-side flow for already-issued checkout sessions (the buyer&#39;s MuHaven wallet signs with their own session key; their pause state is independent).</li></ul><h2 id="how-to-resume" tabindex="-1">How to resume <a class="header-anchor" href="#how-to-resume" aria-label="Permalink to &quot;How to resume&quot;">​</a></h2><p>Resume requires your <strong>master passkey</strong> (not the session key — it was uninstalled, so it can&#39;t authorize a reinstall):</p><ul><li><strong>Dashboard:</strong> <code>/agent → Resume button</code> → passkey ceremony.</li><li><strong>HavenBot:</strong> <em>&quot;Resume my agent.&quot;</em> → opens ConfirmModal → passkey ceremony.</li><li><strong>MCP / Telegram:</strong> can&#39;t drive WebAuthn. Direct user to the dashboard.</li></ul><p>The resume flow:</p><ol><li>You request resume.</li><li>Backend mints an unsigned UserOp: <code>installPlugin(sessionKeyValidator, ...)</code> with fresh scope params.</li><li>Your master passkey signs (WebAuthn ceremony).</li><li>Bundler relays; ~1 block to install.</li><li>Backend writes <code>pause_lifted</code> audit row.</li><li>Cron policy engine re-adds the user.</li></ol><p>After resume, you&#39;re back in your previous tier (resume doesn&#39;t downgrade you). If you want to downgrade as part of resume, use the tier picker in <code>/agent/policy/transition</code>.</p><h2 id="pause-policy-bound-interaction" tabindex="-1">Pause + Policy-bound interaction <a class="header-anchor" href="#pause-policy-bound-interaction" aria-label="Permalink to &quot;Pause + Policy-bound interaction&quot;">​</a></h2><p>If you&#39;re in Policy-bound tier and the cron engine detects a <strong>breach</strong> (e.g., your $500 daily-spend cap is exceeded), the engine <strong>auto-pauses</strong> to Advisory:</p><ol><li>Encrypted threshold check via <code>RiskParams.checkAndExecute</code> returns <code>breach=true</code>.</li><li>Engine async-decrypts the breach (TN decrypt + on-chain <code>settleBreachDecrypt</code>).</li><li>Engine emits a <code>RiskBreach</code> event on-chain.</li><li>Engine calls <code>PauseAgentUseCase</code> for the user (same cascade as a manual pause).</li><li>User notified via Telegram (if linked) + dashboard banner on next sign-in.</li></ol><p>The auto-pause is the <strong>fail-safe</strong> for Policy-bound — bounded autonomy that exits to manual review if bounds are crossed.</p><h2 id="pause-is-not-stop-everything" tabindex="-1">Pause is not &quot;stop everything&quot; <a class="header-anchor" href="#pause-is-not-stop-everything" aria-label="Permalink to &quot;Pause is not &quot;stop everything&quot;&quot;">​</a></h2><p>Important nuance: pause stops <strong>your MuHaven wallet&#39;s session key from signing</strong>. It does <strong>not</strong>:</p><ul><li>Stop pending bundler submissions that were already in-flight when you paused.</li><li>Stop on-chain events that fire as a result of past UserOps (e.g., a <code>Settled</code> event from a buy that was already in the bundler when you paused).</li><li>Roll back any already-settled transactions.</li></ul><p>The brief soft-real-time window between pause and validator uninstall means there&#39;s a small race where an action submitted just before your pause may still settle. Treat pause as &quot;no new actions&quot; rather than &quot;everything reverts.&quot;</p><h2 id="when-pause-matters-most" tabindex="-1">When pause matters most <a class="header-anchor" href="#when-pause-matters-most" aria-label="Permalink to &quot;When pause matters most&quot;">​</a></h2><ul><li><strong>Lost or stolen laptop.</strong> Pause from your phone (<code>/pause</code> in Telegram, or sign in from a different device).</li><li><strong>Suspicious activity in audit log.</strong> Pause first, investigate second.</li><li><strong>Major market move.</strong> Stop the policy-bound cron from automating something into a fast-moving market.</li><li><strong>Maintenance window.</strong> Pause before a personal-side migration (e.g., moving to a new password manager).</li></ul><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/policy/tiered-autonomy">Tiered autonomy</a> — how pause fits the four-tier ladder.</li><li><a href="/policy/session-keys">Session keys</a> — what the validator the pause uninstalls actually authorized.</li><li><a href="/policy/audit-log">Audit log</a> — what pause/resume write to the log.</li></ul>`,36)])])}const g=a(o,[["render",i]]);export{h as __pageData,g as default};
